import React, { useState } from 'react';
import { useAuth } from '../context/SupabaseContext';
import { useBrand } from '../context/BrandContext';
import { useToast } from './ui/Toast';

interface ShareButtonProps {
  contentHtml: string;
  contentType?: string;
  metadata?: Record<string, unknown>;
}

export default function ShareButton({ contentHtml, contentType = 'resume', metadata }: ShareButtonProps) {
  const { user, invokeEdgeFunction } = useAuth();
  const brand = useBrand();
  const { showToast } = useToast();
  const [shareUrl, setShareUrl] = useState<string | null>(null);
  const [isCreating, setIsCreating] = useState(false);
  const [showPanel, setShowPanel] = useState(false);

  async function handleShare() {
    if (!user) {
      showToast('Sign in to share your results.', true);
      return;
    }

    if (shareUrl) {
      setShowPanel(true);
      return;
    }

    setIsCreating(true);
    const { data, error } = await invokeEdgeFunction('create-share-link', {
      contentHtml,
      contentType,
      metadata: metadata || {},
    });

    setIsCreating(false);

    if (error) {
      showToast(error.message, true);
      return;
    }

    const result = data as { url?: string; slug?: string };
    if (result?.url) {
      setShareUrl(result.url);
      setShowPanel(true);
    }
  }

  async function handleCopyLink() {
    if (!shareUrl) return;
    await navigator.clipboard.writeText(shareUrl);
    showToast('Share link copied to clipboard!');
  }

  return (
    <>
      <button
        onClick={handleShare}
        disabled={isCreating}
        className="btn ghost-btn"
      >
        {isCreating ? (
          <><i className="fa-solid fa-spinner fa-spin" /> Creating link...</>
        ) : (
          <><i className="fa-solid fa-share-nodes" /> Share</>
        )}
      </button>

      {showPanel && shareUrl && (
        <div
          className="modal-overlay"
          onClick={(e) => { if (e.target === e.currentTarget) setShowPanel(false); }}
        >
          <div className="modal-dialog md">
            <h3 style={{ margin: '0 0 0.5rem', color: 'var(--text-primary)', fontSize: '1.1rem' }}>
              <i className="fa-solid fa-share-nodes" style={{ color: brand.primaryColor, marginRight: '0.5rem' }} />
              Share Your Results
            </h3>
            <p style={{ color: 'var(--text-secondary)', fontSize: '0.82rem', margin: '0 0 1.25rem' }}>
              Anyone with this link can view your tailored resume and leave feedback. Link expires in 30 days.
            </p>

            <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '1rem' }}>
              <input
                readOnly
                value={shareUrl}
                style={{ flex: 1 }}
              />
              <button
                onClick={handleCopyLink}
                className="btn secondary-btn"
              >
                <i className="fa-solid fa-copy" /> Copy
              </button>
            </div>

            <button
              onClick={() => setShowPanel(false)}
              className="btn ghost-btn"
              style={{ width: '100%' }}
            >
              Close
            </button>
          </div>
        </div>
      )}
    </>
  );
}
