import React from 'react';
import { useBrand } from '../context/BrandContext';

interface Template {
  key: string;
  label: string;
  description: string;
  accent: string;
  fontFamily: string;
}

const TEMPLATES: Template[] = [
  { key: 'executive', label: 'Executive', description: 'Classic serif, gold accents, centered headers', accent: '#A6842A', fontFamily: 'Georgia, serif' },
  { key: 'modern-split', label: 'Modern Split', description: 'Bold sidebar, asymmetric layout', accent: '#5C7A8A', fontFamily: 'system-ui, sans-serif' },
  { key: 'timeline', label: 'Timeline', description: 'Left-border timeline, visual progression', accent: '#5F8A85', fontFamily: 'system-ui, sans-serif' },
  { key: 'minimalist-grid', label: 'Minimalist', description: 'Clean grid, minimal decoration', accent: '#888', fontFamily: "'Helvetica Neue', sans-serif" },
  { key: 'tech-sidebar', label: 'Tech', description: 'Dark sidebar skills, modern layout', accent: '#4A90D9', fontFamily: "'Segoe UI', sans-serif" },
  { key: 'startup', label: 'Startup', description: 'Vibrant colors, rounded badges', accent: '#FF6B6B', fontFamily: "'Inter', sans-serif" },
  { key: 'academic', label: 'Academic', description: 'Structured sections, scholarly feel', accent: '#2C3E50', fontFamily: "'Times New Roman', serif" },
  { key: 'creative', label: 'Creative', description: 'Gradient accents, unique typography', accent: '#8E44AD', fontFamily: "'Poppins', sans-serif" },
  { key: 'federal', label: 'Federal', description: 'Government standard, plain format', accent: '#1a3c5e', fontFamily: "'Times New Roman', serif" },
  { key: 'corporate', label: 'Corporate', description: 'Professional, boardroom-ready', accent: '#2C3E50', fontFamily: "'Calibri', sans-serif" },
  { key: 'infographic', label: 'Infographic', description: 'Skill bars, visual data display', accent: '#E74C3C', fontFamily: "'Montserrat', sans-serif" },
  { key: 'nordic', label: 'Nordic', description: 'Muted tones, elegant spacing', accent: '#607D8B', fontFamily: "'Lato', sans-serif" },
  { key: 'retro', label: 'Retro', description: 'Typewriter style, vintage charm', accent: '#8B4513', fontFamily: "'Courier New', monospace" },
  { key: 'brutalist', label: 'Brutalist', description: 'Bold mono, raw aesthetic', accent: '#000', fontFamily: "'JetBrains Mono', monospace" },
  { key: 'ats-ultra', label: 'ATS Ultra-Safe', description: 'Maximum ATS compatibility, zero frills', accent: '#333', fontFamily: "'Arial', sans-serif" },
];

interface TemplateGalleryProps {
  activeTemplate: string;
  onSelect: (key: string) => void;
  compact?: boolean;
}

export default function TemplateGallery({ activeTemplate, onSelect, compact = false }: TemplateGalleryProps) {
  const brand = useBrand();

  if (compact) {
    return (
      <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap' }}>
        {TEMPLATES.map(t => (
          <button
            key={t.key}
            onClick={() => onSelect(t.key)}
            title={t.description}
            style={{
              padding: '0.35rem 0.75rem',
              borderRadius: '8px',
              border: `1px solid ${activeTemplate === t.key ? brand.primaryColor : 'var(--panel-border)'}`,
              background: activeTemplate === t.key ? `${brand.primaryColor}15` : 'transparent',
              color: activeTemplate === t.key ? brand.primaryColor : 'var(--text-secondary)',
              cursor: 'pointer',
              fontSize: '0.78rem',
              fontWeight: 500,
            }}
          >
            {t.label}
          </button>
        ))}
      </div>
    );
  }

  return (
    <div>
      <h3 style={{ fontSize: '0.9rem', fontWeight: 600, color: 'var(--text-primary)', margin: '0 0 0.75rem' }}>
        <i className="fa-solid fa-palette" style={{ color: brand.primaryColor, marginRight: '0.4rem' }} />
        Choose a Template
      </h3>
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fill, minmax(140px, 1fr))',
        gap: '0.75rem',
      }}>
        {TEMPLATES.map(t => (
          <button
            key={t.key}
            onClick={() => onSelect(t.key)}
            style={{
              padding: '0',
              borderRadius: '10px',
              border: `2px solid ${activeTemplate === t.key ? brand.primaryColor : 'var(--panel-border)'}`,
              background: activeTemplate === t.key ? `${brand.primaryColor}08` : 'var(--panel-bg)',
              cursor: 'pointer',
              overflow: 'hidden',
              textAlign: 'left',
            }}
          >
            {/* Mini preview */}
            <div style={{
              height: '80px',
              padding: '0.5rem',
              background: '#fff',
              display: 'flex',
              flexDirection: 'column',
              gap: '3px',
              overflow: 'hidden',
            }}>
              <div style={{ height: '8px', width: '60%', background: t.accent, borderRadius: '2px', margin: '0 auto' }} />
              <div style={{ height: '4px', width: '80%', background: '#ddd', borderRadius: '2px', margin: '0 auto' }} />
              <div style={{ height: '6px', width: '40%', background: t.accent, borderRadius: '2px', opacity: 0.6, marginTop: '4px' }} />
              <div style={{ height: '3px', width: '90%', background: '#eee', borderRadius: '2px' }} />
              <div style={{ height: '3px', width: '75%', background: '#eee', borderRadius: '2px' }} />
              <div style={{ height: '3px', width: '85%', background: '#eee', borderRadius: '2px' }} />
              <div style={{ height: '6px', width: '35%', background: t.accent, borderRadius: '2px', opacity: 0.6, marginTop: '4px' }} />
              <div style={{ height: '3px', width: '80%', background: '#eee', borderRadius: '2px' }} />
            </div>

            {/* Label */}
            <div style={{ padding: '0.4rem 0.6rem' }}>
              <div style={{
                fontSize: '0.75rem',
                fontWeight: 600,
                color: activeTemplate === t.key ? brand.primaryColor : 'var(--text-primary)',
              }}>
                {t.label}
              </div>
              <div style={{ fontSize: '0.65rem', color: 'var(--text-secondary)', lineHeight: 1.3 }}>
                {t.description}
              </div>
            </div>
          </button>
        ))}
      </div>
    </div>
  );
}

export { TEMPLATES };
