import React, { useState, useRef, useEffect } from 'react';
import { useBrand } from '../context/BrandContext';
import { useToast } from './ui/Toast';

interface ExportMenuProps {
  resumeRef: React.RefObject<HTMLDivElement | null>;
  fileName?: string;
}

export default function ExportMenu({ resumeRef, fileName = 'resume_tailored' }: ExportMenuProps) {
  const brand = useBrand();
  const { showToast } = useToast();
  const [isOpen, setIsOpen] = useState(false);
  const menuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    function handleClick(e: MouseEvent) {
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) {
        setIsOpen(false);
      }
    }
    document.addEventListener('click', handleClick);
    return () => document.removeEventListener('click', handleClick);
  }, []);

  async function exportPDF() {
    const html2pdf = (window as unknown as Record<string, unknown>).html2pdf as {
      default?: () => { set: (opts: unknown) => { from: (el: HTMLElement) => { save: () => void } } };
      (): { set: (opts: unknown) => { from: (el: HTMLElement) => { save: () => void } } };
    };
    const lib = html2pdf?.default || html2pdf;
    if (!lib || !resumeRef.current) {
      showToast('PDF export not available.', true);
      return;
    }
    lib()
      .set({
        margin: [10, 6],
        image: { type: 'jpeg', quality: 0.98 },
        html2canvas: { scale: 2, useCORS: true },
        jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
        pagebreak: { mode: 'avoid-all' },
        filename: `${fileName}.pdf`,
      })
      .from(resumeRef.current)
      .save();
    setIsOpen(false);
    showToast('PDF downloading...');
  }

  async function exportDOCX() {
    try {
      const htmlDocx = (window as unknown as Record<string, unknown>).htmlDocx as {
        asBlob: (html: string) => Blob;
      };
      if (!htmlDocx || !resumeRef.current) {
        showToast('DOCX export not available. Try PDF instead.', true);
        return;
      }
      const html = `<!DOCTYPE html><html><head><meta charset="utf-8"><style>body{font-family:Calibri,sans-serif;font-size:11pt;}</style></head><body>${resumeRef.current.innerHTML}</body></html>`;
      const blob = htmlDocx.asBlob(html);
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `${fileName}.docx`;
      a.click();
      URL.revokeObjectURL(url);
      setIsOpen(false);
      showToast('DOCX downloading...');
    } catch {
      showToast('DOCX export failed. Try PDF instead.', true);
    }
  }

  async function exportTXT() {
    if (!resumeRef.current) return;
    const text = resumeRef.current.innerText || '';
    const blob = new Blob([text], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${fileName}.txt`;
    a.click();
    URL.revokeObjectURL(url);
    setIsOpen(false);
    showToast('TXT downloading...');
  }

  async function copyToClipboard() {
    if (!resumeRef.current) return;
    const text = resumeRef.current.innerText || '';
    await navigator.clipboard.writeText(text);
    setIsOpen(false);
    showToast('Copied to clipboard!');
  }

  const options = [
    { icon: 'fa-file-pdf', label: 'PDF', description: 'Best for applications', action: exportPDF },
    { icon: 'fa-file-word', label: 'DOCX', description: 'Editable in Word/Docs', action: exportDOCX },
    { icon: 'fa-file-lines', label: 'Plain Text', description: 'Copy-paste friendly', action: exportTXT },
    { icon: 'fa-clipboard', label: 'Clipboard', description: 'Copy formatted text', action: copyToClipboard },
  ];

  return (
    <div ref={menuRef} style={{ position: 'relative', display: 'inline-block' }}>
      <button
        onClick={() => setIsOpen(!isOpen)}
        style={{
          padding: '0.6rem 1.25rem',
          borderRadius: '10px',
          background: brand.primaryColor,
          color: '#fff',
          border: 'none',
          fontWeight: 600,
          fontSize: '0.85rem',
          cursor: 'pointer',
          display: 'inline-flex',
          alignItems: 'center',
          gap: '0.4rem',
        }}
      >
        <i className="fa-solid fa-download" /> Export
        <i className={`fa-solid fa-chevron-${isOpen ? 'up' : 'down'}`} style={{ fontSize: '0.65rem', marginLeft: '0.2rem' }} />
      </button>

      {isOpen && (
        <div style={{
          position: 'absolute',
          top: 'calc(100% + 4px)',
          left: 0,
          background: 'var(--panel-bg)',
          border: '1px solid var(--panel-border)',
          borderRadius: '10px',
          overflow: 'hidden',
          zIndex: 50,
          boxShadow: '0 4px 16px rgba(0,0,0,0.2)',
          minWidth: '200px',
        }}>
          {options.map(opt => (
            <button
              key={opt.label}
              onClick={opt.action}
              style={{
                width: '100%',
                padding: '0.6rem 0.75rem',
                background: 'transparent',
                border: 'none',
                borderBottom: '1px solid var(--panel-border)',
                color: 'var(--text-primary)',
                fontSize: '0.82rem',
                textAlign: 'left',
                cursor: 'pointer',
                display: 'flex',
                alignItems: 'center',
                gap: '0.6rem',
              }}
            >
              <i className={`fa-solid ${opt.icon}`} style={{ width: '16px', textAlign: 'center', color: brand.primaryColor }} />
              <div>
                <div style={{ fontWeight: 600 }}>{opt.label}</div>
                <div style={{ fontSize: '0.7rem', color: 'var(--text-secondary)' }}>{opt.description}</div>
              </div>
            </button>
          ))}
        </div>
      )}
    </div>
  );
}
