import React, { useEffect, useState, useRef } from 'react';
import { useNavigate, useSearchParams, Link } from 'react-router-dom';
import { useAuth } from '../context/SupabaseContext';
import { useBrand } from '../context/BrandContext';
import { useToast } from '../components/ui/Toast';
import ShareButton from '../components/ShareButton';
import TemplateGallery from '../components/TemplateGallery';
import ExportMenu from '../components/ExportMenu';

interface TmsOutputs {
  resumeHtml: string;
  matchScore?: number;
  applicantName?: string;
  targetCompany?: string;
  missingKeywords?: string[];
  rawText?: string;
  metadata?: Record<string, unknown>;
}

export default function ResultsPage() {
  const { user, supabase } = useAuth();
  const brand = useBrand();
  const { showToast } = useToast();
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const resumeRef = useRef<HTMLDivElement>(null);
  const [outputs, setOutputs] = useState<TmsOutputs | null>(null);
  const [activeTemplate, setActiveTemplate] = useState('executive');
  const [fromDb, setFromDb] = useState(false);

  useEffect(() => {
    const genId = searchParams.get('id');

    if (genId && user) {
      async function loadFromDb() {
        const { data } = await supabase
          .from('generations')
          .select('resume_html, match_score, target_company, applicant_name, missing_keywords')
          .eq('id', genId)
          .eq('user_id', user!.id)
          .single();

        if (data) {
          setOutputs({
            resumeHtml: data.resume_html,
            matchScore: data.match_score,
            applicantName: data.applicant_name,
            targetCompany: data.target_company,
            missingKeywords: data.missing_keywords || [],
          });
          setFromDb(true);
        } else {
          navigate('/dashboard');
        }
      }
      loadFromDb();
      return;
    }

    const raw = sessionStorage.getItem('tms_outputs');
    if (!raw) {
      navigate('/app');
      return;
    }
    try {
      setOutputs(JSON.parse(raw));
    } catch {
      navigate('/app');
    }
  }, [navigate, searchParams, user, supabase]);

  useEffect(() => {
    if (!outputs || !user || fromDb) return;
    async function save() {
      await supabase.from('generations').insert({
        user_id: user!.id,
        resume_html: outputs!.resumeHtml,
        match_score: outputs!.matchScore || 0,
        target_company: outputs!.targetCompany || '',
        applicant_name: outputs!.applicantName || '',
        missing_keywords: outputs!.missingKeywords || [],
        application_status: 'Tailored',
      });
    }
    save();
  }, [outputs, user, supabase, fromDb]);

  if (!outputs) return null;

  return (
    <div style={{ maxWidth: '1000px', margin: '0 auto', padding: '2rem 1.5rem' }}>
      {/* Score & Meta */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '1.5rem', flexWrap: 'wrap', gap: '1rem' }}>
        <div>
          <h1 style={{ fontSize: '1.5rem', margin: '0 0 0.25rem', color: 'var(--text-primary)' }}>
            {outputs.applicantName ? `${outputs.applicantName}'s Tailored Resume` : 'Your Tailored Resume'}
          </h1>
          {outputs.targetCompany && (
            <p style={{ color: 'var(--text-secondary)', fontSize: '0.85rem', margin: 0 }}>
              Tailored for {outputs.targetCompany}
            </p>
          )}
        </div>
        {typeof outputs.matchScore === 'number' && (
          <div className="small-btn" style={{
            padding: '0.5rem 1rem',
            background: outputs.matchScore >= 80 ? 'rgba(16,185,129,0.15)' : outputs.matchScore >= 60 ? 'rgba(245,158,11,0.15)' : 'rgba(239,68,68,0.15)',
            color: outputs.matchScore >= 80 ? '#10b981' : outputs.matchScore >= 60 ? '#f59e0b' : '#ef4444',
            fontWeight: 700,
            fontSize: '1.1rem',
            border: 'none',
          }}>
            {outputs.matchScore}% Match
          </div>
        )}
      </div>

      {/* Missing Keywords */}
      {outputs.missingKeywords && outputs.missingKeywords.length > 0 && (
        <div className="glass-panel" style={{
          padding: '0.75rem 1rem',
          marginBottom: '1.5rem',
          background: 'rgba(245,158,11,0.08)',
          borderColor: 'rgba(245,158,11,0.3)',
        }}>
          <span style={{ fontSize: '0.8rem', fontWeight: 600, color: '#f59e0b' }}>
            <i className="fa-solid fa-triangle-exclamation" /> Missing Keywords:
          </span>
          <span style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', marginLeft: '0.5rem' }}>
            {outputs.missingKeywords.join(', ')}
          </span>
        </div>
      )}

      {/* Template Selector */}
      <div style={{ marginBottom: '1rem' }}>
        <TemplateGallery activeTemplate={activeTemplate} onSelect={setActiveTemplate} compact />
      </div>

      {/* Resume Preview */}
      <div
        ref={resumeRef}
        className={`resume-output rich-output-area theme-${activeTemplate}`}
        style={{
          background: '#fff',
          color: '#2A2E38',
          padding: '2rem',
          marginBottom: '1.5rem',
        }}
        dangerouslySetInnerHTML={{ __html: outputs.resumeHtml }}
      />

      {/* Action Buttons */}
      <div style={{ display: 'flex', gap: '0.75rem', flexWrap: 'wrap', alignItems: 'flex-start' }}>
        <ExportMenu
          resumeRef={resumeRef}
          fileName={`${outputs.applicantName || 'resume'}_tailored`}
        />
        <Link to="/resume" className="btn ghost-btn" style={{ textDecoration: 'none' }}>
          <i className="fa-solid fa-pen" /> Edit in Builder
        </Link>
        <Link to="/tailor" className="btn ghost-btn" style={{ textDecoration: 'none' }}>
          <i className="fa-solid fa-rotate" /> Tailor Another
        </Link>
        <ShareButton
          contentHtml={outputs.resumeHtml}
          contentType="resume"
          metadata={{
            applicantName: outputs.applicantName,
            targetCompany: outputs.targetCompany,
            matchScore: outputs.matchScore,
          }}
        />
      </div>
    </div>
  );
}
